compliant:
class MyClass : SomeBase
{
    public override bool Equals(object other)
    {
        if (ReferenceEquals(this, other)) // Compliant - using ReferenceEquals
            return true;
        // ... rest of implementation
    }
}

class MyClass : object // Direct object inheritance
{
    public override bool Equals(object other)
    {
        if (base.Equals(other)) // Compliant - base is object
            return true;
        // ... rest of implementation
    }
}
